    #[test]
    fn phi3_kv_cache_full_model_alloc() {
        // Whole-model alloc: 32 layers, 32 KV heads, head_dim=96.
        let cache = phi3_kv_cache(32, 32, 96, None, None);
        assert_eq!(cache.base_layer, 0);
        assert_eq!(cache.num_layers, 32);
        assert_eq!(cache.num_kv_heads, 32);
        assert_eq!(cache.head_dim, 96);
        assert_eq!(cache.max_seq_len, PHI3_KV_MAX_SEQ_LEN);
        let expected_size = 32 * 32 * PHI3_KV_MAX_SEQ_LEN * 96;
        assert_eq!(cache.keys.len(), expected_size);
        assert_eq!(cache.values.len(), expected_size);
    }

    #[test]
    fn phi3_kv_cache_trisplit_carve() {
        // Worker owning layers [5..8): kv_base=5, kv_num_layers=3.
        // This is the gemma4 trisplit pattern transferred to phi3.
        let cache = phi3_kv_cache(32, 32, 96, Some(5), Some(3));
        assert_eq!(cache.base_layer, 5);
        assert_eq!(cache.num_layers, 3);
        let expected_size = 3 * 32 * PHI3_KV_MAX_SEQ_LEN * 96;
        assert_eq!(cache.keys.len(), expected_size);
        assert_eq!(cache.values.len(), expected_size);
        // Layer 5 must map to local slot 0 (verified via the layer
        // offset helper that gemma4 uses for cache addressing).
        assert_eq!(cache.get_key_layer_offset(5), 0);
        assert_eq!(
            cache.get_key_layer_offset(7),
            2 * 32 * PHI3_KV_MAX_SEQ_LEN * 96
        );
    }

