    #[test]
    fn apply_phi3_rope_pos_zero_is_identity() {
        // At pos=0, sin=0 cos=1 for every freq, so RoPE is identity.
        let mut q = vec![0.5_f32, 1.5, -0.25, 2.0];
        let original = q.clone();
        apply_phi3_rope(&mut q, 0, 1, 4, 10000.0);
        for (a, b) in q.iter().zip(original.iter()) {
            assert!(
                (a - b).abs() < 1e-6,
                "pos-0 rotation should be identity, got {a} vs {b}"
            );
        }
    }

    #[test]
    fn apply_phi3_rope_known_vector_head_dim_4() {
        // Hand-computed reference for one head of head_dim=4 at pos=1
        // with theta=10000.0 and NeoX pairing (i, i+2):
        //   freq_0 = 1 / 10000^(0/4) = 1.0
        //   freq_1 = 1 / 10000^(2/4) = 1/100 = 0.01
        //   pos*freq_0 = 1.0   -> sin=0.84147098, cos=0.54030231
        //   pos*freq_1 = 0.01  -> sin=0.00999983, cos=0.99995000
        // Input q = [1, 2, 3, 4] (q[0..2] is "lower half", q[2..4] "upper").
        //   q'[0] = 1*cos(1) - 3*sin(1) = 0.54030 - 2.52441 = -1.98411
        //   q'[2] = 1*sin(1) + 3*cos(1) = 0.84147 + 1.62091 =  2.46238
        //   q'[1] = 2*cos(.01) - 4*sin(.01) = 1.99990 - 0.04000 =  1.95991
        //   q'[3] = 2*sin(.01) + 4*cos(.01) = 0.02000 + 3.99980 =  4.01980
        let mut q = vec![1.0_f32, 2.0, 3.0, 4.0];
        apply_phi3_rope(&mut q, 1, 1, 4, 10000.0);
        let expected = [-1.984111_f32, 1.959997, 2.462378, 4.019800];
        for (i, (got, want)) in q.iter().zip(expected.iter()).enumerate() {
            assert!(
                (got - want).abs() < 1e-4,
                "RoPE element {i}: got {got}, want {want}"
            );
        }
    }

    #[test]
    fn apply_phi3_rope_qk_phi3_mini_dims() {
        // Smoke: rotate Q (32 heads × 96) and K (32 heads × 96) at pos=5
        // with the canonical Phi-3-mini params. Just check no panic
        // and that the buffers remain finite.
        let mut q = vec![0.1_f32; 32 * 96];
        let mut k = vec![-0.2_f32; 32 * 96];
        apply_phi3_rope_qk(&mut q, &mut k, 5, 32, 32, 96, PHI3_ROPE_THETA_DEFAULT);
        assert!(q.iter().all(|v| v.is_finite()));
        assert!(k.iter().all(|v| v.is_finite()));
        // Energy is preserved by rotation (per-pair sum-of-squares).
        let q_energy: f32 = q.iter().map(|v| v * v).sum();
        let expected = 32.0 * 96.0 * 0.1 * 0.1;
        assert!(
            (q_energy - expected).abs() / expected < 1e-3,
            "RoPE should preserve energy: got {q_energy}, want {expected}"
        );
    }

