    #[test]
    fn phi3_swa_mask_row_below_window_is_all_zero() {
        // pos < window: mask is empty (just causal attn_len).
        let row = phi3_swa_mask_row(10, 11, PHI3_SLIDING_WINDOW);
        assert_eq!(row.len(), 11);
        assert!(row.iter().all(|&m| m == 0.0));
    }

    #[test]
    fn phi3_swa_mask_row_above_window_cuts_tail() {
        // pos = 3000, window = 2048: keys [0, 953) are masked, keys
        // [953, 3001) are open. window_start = 3000 - 2047 = 953.
        let row = phi3_swa_mask_row(3000, 3001, PHI3_SLIDING_WINDOW);
        assert_eq!(row.len(), 3001);
        for (k, &m) in row.iter().enumerate() {
            if k < 953 {
                assert_eq!(m, f32::NEG_INFINITY, "key {k} should be masked");
            } else {
                assert_eq!(m, 0.0, "key {k} should be open");
            }
        }
    }

    #[test]
    fn phi3_swa_mask_matrix_diagonal_band_at_seq_4096() {
        // seq_len = 4096, window = 2048, start_pos = 0.
        // The mask should look like:
        //   - upper triangle (k > i): -inf  (causal)
        //   - lower triangle within 2048 of diagonal: 0
        //   - lower triangle further than 2048 from diagonal: -inf (SWA)
        let seq = 4096;
        let window = PHI3_SLIDING_WINDOW;
        let mat = phi3_swa_mask_matrix(0, seq, window);
        assert_eq!(mat.len(), seq * seq);

        // Spot-check four corners:
        // (0,0): on the diagonal, in-window -> 0
        assert_eq!(mat[0], 0.0);
        // (4095, 4095): on the diagonal -> 0
        assert_eq!(mat[(seq - 1) * seq + (seq - 1)], 0.0);
        // (4095, 0): distance 4095, beyond window -> -inf
        assert_eq!(mat[(seq - 1) * seq], f32::NEG_INFINITY);
        // (0, 4095): future key, causal -> -inf
        assert_eq!(mat[seq - 1], f32::NEG_INFINITY);

        // Diagonal-band check on row 3000:
        //   - keys [952, 3000] open
        //   - keys [0, 952) masked (SWA)
        //   - keys (3000, 4096) masked (causal)
        let row_off = 3000 * seq;
        for j in 0..seq {
            let cell = mat[row_off + j];
            let in_band = j >= 953 && j <= 3000;
            if in_band {
                assert_eq!(cell, 0.0, "row 3000 col {j} should be open");
            } else {
                assert_eq!(cell, f32::NEG_INFINITY, "row 3000 col {j} should be masked");
            }
        }
    }

    #[test]
    fn phi3_swa_mask_matrix_below_window_is_pure_causal() {
        // At seq_len <= window the SWA cap never fires; mask reduces
        // to the standard causal lower-triangular shape.
        let seq = 1024; // < PHI3_SLIDING_WINDOW
        let mat = phi3_swa_mask_matrix(0, seq, PHI3_SLIDING_WINDOW);
        for i in 0..seq {
            for j in 0..seq {
                let cell = mat[i * seq + j];
                if j > i {
                    assert_eq!(cell, f32::NEG_INFINITY);
                } else {
                    assert_eq!(cell, 0.0);
                }
            }
        }
    }

