    fn phi3_swa_mask_window_zero_is_no_swa() {
        // window=0 sentinel should disable SWA masking entirely.
        let row = phi3_swa_mask_row(10000, 10001, 0);
        assert!(row.iter().all(|&m| m == 0.0));
    }

