    // ─── RMSNORM ─────────────────────────────────────────────────────

    #[test]
    fn phi3_rmsnorm_uses_llama_convention_not_gemma_shift() {
        // For x = [3, 4] and w = [1, 1]:
        //   rms = sqrt((9 + 16) / 2 + eps) ≈ sqrt(12.5 + 1e-5) ≈ 3.5355
        //   inv = 1 / 3.5355
        //   out = [3 * inv * 1, 4 * inv * 1] ≈ [0.84853, 1.13137]
        // (NOT [3*inv*(1+1), 4*inv*(1+1)] which would be the Gemma3 shift.)
        let x = [3.0_f32, 4.0];
        let w = [1.0_f32, 1.0];
        let mut out = [0.0_f32; 2];
        phi3_rmsnorm(&mut out, &x, &w);
        let expected_inv = 1.0_f32 / ((25.0 / 2.0 + PHI3_RMS_NORM_EPS).sqrt());
        let want_0 = 3.0 * expected_inv;
        let want_1 = 4.0 * expected_inv;
        assert!(
            (out[0] - want_0).abs() < 1e-5,
            "out[0]={} != want={}",
            out[0],
            want_0
        );
        assert!(
            (out[1] - want_1).abs() < 1e-5,
            "out[1]={} != want={}",
            out[1],
            want_1
        );
    }

    #[test]
    fn phi3_rmsnorm_with_eps_overrides_default() {
        let x = [1.0_f32, 1.0, 1.0, 1.0];
        let w = [1.0_f32, 1.0, 1.0, 1.0];
        let mut out_default = [0.0_f32; 4];
        let mut out_loose = [0.0_f32; 4];
        phi3_rmsnorm(&mut out_default, &x, &w);
        phi3_rmsnorm_with_eps(&mut out_loose, &x, &w, 1.0); // huge eps
                                                            // Loose eps should give a different (smaller-scale) result.
        assert!(
            (out_default[0] - out_loose[0]).abs() > 1e-3,
            "eps override should change the result"
        );
    }

    // ─── ATTENTION COMPUTE ───────────────────────────────────────────

    #[test]
    fn phi3_attn_scale_matches_inverse_sqrt_head_dim() {
        // head_dim = 96 (phi3-mini): scale = 1/sqrt(96) ≈ 0.10206
        let s = phi3_attn_scale(96);
        assert!((s - 0.10206_f32).abs() < 1e-4, "scale={s}");
        // head_dim = 64: scale = 1/8 = 0.125
        assert!((phi3_attn_scale(64) - 0.125).abs() < 1e-6);
    }

    #[test]
    fn phi3_attention_one_head_pure_causal_uniform_kv() {
        // head_dim = 4, attn_len = 3, V is identical across all keys
        // -> output should equal that constant V row regardless of Q.
        let head_dim = 4;
        let attn_len = 3;
        let q = [0.5_f32, -0.25, 1.0, 0.0];
        let k = vec![0.1_f32; attn_len * head_dim]; // identical K rows
        let v = {
            // Each row is [1, 2, 3, 4]
            let mut v = Vec::with_capacity(attn_len * head_dim);
            for _ in 0..attn_len {
                v.extend_from_slice(&[1.0_f32, 2.0, 3.0, 4.0]);
            }
            v
        };
        let mut out = [0.0_f32; 4];
        let mut scores = [0.0_f32; 8];
        let scale = phi3_attn_scale(head_dim);

        phi3_attention_one_head(
            &q,
            &k,
            &v,
            &mut out,
            &mut scores,
            /*query_pos=*/ 2,
            attn_len,
            head_dim,
            /*window_size=*/ 0, // SWA disabled
            scale,
        );

        // With identical K rows, all scores tie -> softmax is uniform
        // 1/3 across 3 keys -> weighted sum is just the V row.
        for (i, want) in [1.0, 2.0, 3.0, 4.0].iter().enumerate() {
            assert!(
                (out[i] - want).abs() < 1e-5,
                "out[{i}]={} != {want}",
                out[i]
            );
        }
        // And softmax should normalize to 1.
        let sum: f32 = scores[..attn_len].iter().sum();
        assert!((sum - 1.0).abs() < 1e-5, "softmax sum={sum}");
    }

    #[test]
    fn phi3_attention_one_head_swa_masks_out_of_window_keys() {
        // head_dim = 2, attn_len = 5, window = 2, query_pos = 4.
        // Window covers keys [3, 4]. Keys [0, 1, 2] should be masked
        // out and contribute zero to the output.
        let head_dim = 2;
        let attn_len = 5;
        let window = 2;
        let q = [1.0_f32, 0.0];

        // K rows: 0..4 are arbitrary; 3, 4 give large/small scores.
        let k = vec![
            10.0_f32, 0.0, // row 0 (would dominate if not masked)
            10.0, 0.0, // row 1 (likewise)
            10.0, 0.0, // row 2 (likewise)
            1.0, 0.0, // row 3 (in window)
            2.0, 0.0, // row 4 (in window, larger)
        ];
        // V rows: masked rows have a poison value; in-window rows have
        // [1] and [10]. Output should mix only the in-window rows.
        let v = vec![
            999.0_f32, 999.0, // row 0 (masked)
            999.0, 999.0, // row 1 (masked)
            999.0, 999.0, // row 2 (masked)
            1.0, 1.0, // row 3
            10.0, 10.0, // row 4
        ];

        let mut out = [0.0_f32; 2];
        let mut scores = [0.0_f32; 5];
        let scale = phi3_attn_scale(head_dim);

        phi3_attention_one_head(
            &q,
            &k,
            &v,
            &mut out,
            &mut scores,
            /*query_pos=*/ 4,
            attn_len,
            head_dim,
            window,
            scale,
        );

        // Masked rows must have probability 0.
        for i in 0..3 {
            assert_eq!(
                scores[i], 0.0,
                "masked key {i} should have softmax weight 0"
            );
        }
        // In-window mass should sum to 1.
        let in_window_mass = scores[3] + scores[4];
        assert!(
            (in_window_mass - 1.0).abs() < 1e-5,
            "in-window mass={in_window_mass}"
        );
        // Output must lie strictly between row 3 [1,1] and row 4 [10,10]
        // (since both have weight in (0, 1)).
        assert!(
            out[0] > 1.0 && out[0] < 10.0,
            "out[0]={} outside in-window V range",
            out[0]
        );
        assert!(
            (out[0] - out[1]).abs() < 1e-6,
            "rows are diagonal, components should match"
        );
    }

    #[test]
    fn phi3_attention_one_head_window_zero_equals_no_swa() {
        // window=0 should behave identically to a window large enough
        // to cover every key (pure causal attn, all keys participate).
        let head_dim = 2;
        let attn_len = 4;
        let q = [0.7_f32, -0.3];
        let k: Vec<f32> = (0..attn_len * head_dim).map(|i| (i as f32) * 0.1).collect();
        let v: Vec<f32> = (0..attn_len * head_dim)
            .map(|i| (i as f32) * 0.05)
            .collect();

        let mut out_a = [0.0_f32; 2];
        let mut out_b = [0.0_f32; 2];
        let mut scores_a = [0.0_f32; 4];
        let mut scores_b = [0.0_f32; 4];
        let scale = phi3_attn_scale(head_dim);

        phi3_attention_one_head(
            &q,
            &k,
            &v,
            &mut out_a,
            &mut scores_a,
            3,
            attn_len,
            head_dim,
            0,
            scale,
        );
        phi3_attention_one_head(
            &q,
            &k,
            &v,
            &mut out_b,
            &mut scores_b,
            3,
            attn_len,
            head_dim,
            4096,
            scale,
        );

        for i in 0..2 {
            assert!(
                (out_a[i] - out_b[i]).abs() < 1e-6,
                "window=0 vs window=∞ differ at {i}: {} vs {}",
                out_a[i],
                out_b[i]
            );
        }
    }

    // ─── SWIGLU FFN ──────────────────────────────────────────────────

    #[test]
    fn phi3_swiglu_ffn_f32_identity_weights_collapses_to_silu_squared() {
        // hidden = 2, intermediate = 2, gate_w = up_w = down_w = identity.
        //   gate(x) = x; up(x) = x; mid = silu(x) * x; out = mid.
        // Pick x = [1, 2]. silu(1) ≈ 0.7311, silu(2) ≈ 1.7616.
        // mid = [0.7311*1, 1.7616*2] ≈ [0.7311, 3.5232]
        // out = identity * mid = mid.
        let hidden = 2;
        let intermediate = 2;
        let x = [1.0_f32, 2.0];

        // 2x2 identity row-major
        let id = [1.0_f32, 0.0, 0.0, 1.0];
        let mut gate_s = [0.0_f32; 2];
        let mut up_s = [0.0_f32; 2];
        let mut out = [0.0_f32; 2];

        phi3_swiglu_ffn_f32(
            &mut out,
            &x,
            &id,
            &id,
            &id,
            &mut gate_s,
            &mut up_s,
            hidden,
            intermediate,
        );

        let silu = |x: f32| x / (1.0 + (-x).exp());
        let want = [silu(1.0) * 1.0, silu(2.0) * 2.0];
        for i in 0..2 {
            assert!(
                (out[i] - want[i]).abs() < 1e-5,
                "out[{i}]={} != want={}",
                out[i],
                want[i]
            );
        }
    }

    #[test]
    fn phi3_swiglu_ffn_f32_zero_gate_zeros_output() {
        // If gate_w = 0 then silu(0) = 0 so the whole hidden activation
        // is zero regardless of up / down.
        let hidden = 4;
        let intermediate = 8;
        let x = vec![0.5_f32; hidden];
        let zero_gate = vec![0.0_f32; intermediate * hidden];
        let up_w: Vec<f32> = (0..intermediate * hidden)
            .map(|i| (i as f32) * 0.01)
            .collect();
        let down_w: Vec<f32> = (0..hidden * intermediate)
            .map(|i| (i as f32) * 0.01)
            .collect();
        let mut gate_s = vec![0.0_f32; intermediate];
        let mut up_s = vec![0.0_f32; intermediate];
        let mut out = vec![1.0_f32; hidden]; // pre-fill non-zero

        phi3_swiglu_ffn_f32(
            &mut out,
            &x,
            &zero_gate,
            &up_w,
            &down_w,
            &mut gate_s,
            &mut up_s,
            hidden,
            intermediate,
        );

        for (i, &v) in out.iter().enumerate() {
            assert!(
                v.abs() < 1e-6,
                "out[{i}]={v} should be zero when gate is zero"
            );
        }
    }

    #[test]
    fn phi3_swiglu_ffn_f32_phi3_mini_dims_runs_finite() {
        // Smoke at the real phi3-mini dims with random-ish weights.
        // Just check no panic + finite output.
        let hidden = 64; // shrunk for test cost (real is 3072)
        let intermediate = 128; // real is 8192
        let x: Vec<f32> = (0..hidden).map(|i| ((i as f32) * 0.013).sin()).collect();
        let gate_w: Vec<f32> = (0..intermediate * hidden)
            .map(|i| (((i as f32) * 0.011).cos() - 0.5) * 0.1)
            .collect();
        let up_w: Vec<f32> = (0..intermediate * hidden)
            .map(|i| (((i as f32) * 0.007).sin()) * 0.1)
            .collect();
        let down_w: Vec<f32> = (0..hidden * intermediate)
            .map(|i| (((i as f32) * 0.005).cos()) * 0.1)
            .collect();
        let mut gate_s = vec![0.0_f32; intermediate];
        let mut up_s = vec![0.0_f32; intermediate];
        let mut out = vec![0.0_f32; hidden];

        phi3_swiglu_ffn_f32(
            &mut out,
            &x,
            &gate_w,
            &up_w,
            &down_w,
            &mut gate_s,
            &mut up_s,
            hidden,
            intermediate,
        );

        assert!(out.iter().all(|v| v.is_finite()), "FFN output not finite");
    }

