    // ─── PIPELINE CONSTRUCTION GAP CHECK ─────────────────────────────

    #[test]
    fn phi3_pipeline_from_knot_surfaces_encoder_gap_cleanly() {
        // Build a synthetic knot with the Phi-3 config block but NO
        // tensor metadata. `from_knot_with_kv_range` should return
        // ENCODER_GAP at the fused-tensor preflight, not panic deep in
        // resolve_tensor.
        use crate::loader::KnotConfig;

        let config = KnotConfig {
            hidden_dim: 3072,
            num_layers: 32,
            num_heads: 32,
            num_kv_heads: 32,
            head_dim: 96,
            intermediate_size: 8192,
            vocab_size: 32064,
            rms_norm_eps: PHI3_RMS_NORM_EPS,
            rope_theta: PHI3_ROPE_THETA_DEFAULT,
            arch: "phi3".to_string(),
            final_logit_softcap: None,
            query_pre_attn_scalar: None,
            sliding_window_pattern: None,
            sliding_window: Some(PHI3_SLIDING_WINDOW),
            global_head_dim: None,
            global_num_kv_heads: None,
            rope_local_base_freq: None,
            rope_scaling_factor: None,
            rope_partial_factor: None,
            d_state: None,
            d_conv: None,
            ssm_expand: None,
            dt_rank: None,
            ssm_n_groups: None,
            ssm_chunk_size: None,
            rwkv_n_heads: None,
            rwkv_low_rank_w: None,
            rwkv_low_rank_a: None,
            rwkv_low_rank_v: None,
            rwkv_gate_inner: None,
            hybrid_attn_layer_period: None,
            max_seq_len: None,
            num_experts: None,
            num_experts_per_tok: None,
        };

        // Empty backend (no tensors); just need a WeightBackend impl.
        // Reuse the test-only `EmptyBackend` defined below.
        use crate::loader::{KnotWeights, OwnedBytes, WeightBackend};
        use std::sync::Arc;

        struct EmptyBackend;
        impl WeightBackend for EmptyBackend {
            fn fetch_tensor(&self, name: &str) -> std::result::Result<OwnedBytes, String> {
                Err(format!("no tensor {} in EmptyBackend", name))
            }
            fn has_tensor(&self, _name: &str) -> bool {
                false
            }
            fn as_any(&self) -> &dyn std::any::Any {
                self
            }
        }

        let knot = KnotWeights::from_parts(
            Arc::new(EmptyBackend),
            std::collections::HashMap::new(),
            Some(config),
            0,
        );
        let err = match Phi3Pipeline::from_knot(knot) {
            Err(e) => e,
            Ok(_) => panic!("empty knot should error at the encoder-gap preflight"),
        };
        assert!(
            err.contains("encoder needs to emit fused tensor names"),
            "expected ENCODER_GAP error, got: {}",
            err
        );
    }

